insert into public.faq_entries (id, question, answer, category, sort_order, is_active) values ('09bfb5f3-40c8-58fa-88c0-0763f014deab', 'How is this different from other coaching or habit apps?', 'Most apps reset to zero context every session. Executive Coach AI builds a persistent behavioral model of you over months — tracking your task completion patterns, emotional triggers, and avoidance cycles. The coaching quality compounds the longer you use it, so your weekly retrospectives get sharper and more personal over time.', 'Getting Started', 1, true) on conflict (id) do nothing;
insert into public.faq_entries (id, question, answer, category, sort_order, is_active) values ('e9e0784a-3a00-5f74-84d3-9b6a2a0b1369', 'What exactly is a weekly retrospective?', 'Every week, the app generates a structured review built FROM your own behavioral history — not generic advice. It surfaces patterns like which projects you stalled on, what time of day you tend to avoid hard tasks, and which triggers preceded a drift. You get concrete, evidence-based observations and a focused plan for the week ahead.', 'Features', 2, true) on conflict (id) do nothing;
insert into public.faq_entries (id, question, answer, category, sort_order, is_active) values ('d320225d-4a90-5fee-8c76-7ff45e7fe6f5', 'Is this designed for people with ADHD?', 'Yes. It''s built specifically for professionals earning $60K+ who have ADHD and can''t afford an executive coach. The real-time nudges detect when you''re drifting from intentions and intervene in the moment, while the long-term model accounts for the executive-function patterns common with ADHD instead of assuming neurotypical willpower.', 'Getting Started', 3, true) on conflict (id) do nothing;
insert into public.faq_entries (id, question, answer, category, sort_order, is_active) values ('952b9cb7-9155-59e9-8594-5ea61cb7c782', 'How do the real-time nudges work?', 'The app watches for drift — when your behavior starts diverging from your stated goals or known productive patterns — and sends a timely nudge to redirect you. Because it learns your personal triggers and avoidance cycles, nudges become more accurate and less annoying the longer you stay.', 'Features', 4, true) on conflict (id) do nothing;
insert into public.faq_entries (id, question, answer, category, sort_order, is_active) values ('89fee4e4-1777-5255-83b8-f1ed55216b1f', 'What happens to my behavioral data and is it private?', 'Your behavioral history is the core asset that makes coaching better over time, so it''s stored securely and used only to model and coach you. We don''t sell your data. You can export or delete your history at any time from settings.', 'Privacy & Data', 5, true) on conflict (id) do nothing;
